import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Heart, ListPlus, Play, Pause, Music, CheckCircle2, Circle, X, SkipBack, SkipForward } from 'lucide-react';

const Home = () => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  
  const [isSelecting, setIsSelecting] = useState(false);
  const [newPlaylistTitle, setNewPlaylistTitle] = useState("");
  const [selectedSongIds, setSelectedSongIds] = useState([]);

  const audioRef = useRef(null);
  const navigate = useNavigate();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchSongs();
  }, []);

  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) { console.error("Lỗi tải nhạc:", err); }
  };

  // Logic điều khiển nhạc
  const handleNext = () => {
    if (songs.length === 0) return;
    setCurrentIndex((prev) => (prev + 1) % songs.length);
  };

  const handlePrev = () => {
    if (songs.length === 0) return;
    setCurrentIndex((prev) => (prev - 1 + songs.length) % songs.length);
  };

  const onTimeUpdate = () => {
    const current = audioRef.current.currentTime;
    const total = audioRef.current.duration;
    setProgress((current / total) * 100 || 0);
  };

  const handleSeek = (e) => {
    const seekTime = (e.target.value / 100) * audioRef.current.duration;
    audioRef.current.currentTime = seekTime;
    setProgress(e.target.value);
  };

  const handleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    try {
      const res = await axios.post(`http://localhost:5000/api/songs/like/${songId}`, {
        userId: loggedInUser._id || loggedInUser.id
      });
      setSongs(songs.map(s => s._id === songId ? res.data : s));
    } catch (err) { console.error(err); }
  };

  const handleStartCreatePlaylist = () => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    const title = prompt("Nhập tên cho Playlist mới:");
    if (!title) return;
    setNewPlaylistTitle(title);
    setIsSelecting(true);
    setSelectedSongIds([]);
  };

  const toggleSongSelection = (songId) => {
    setSelectedSongIds(prev => prev.includes(songId) ? prev.filter(id => id !== songId) : [...prev, songId]);
  };

  const handleSavePlaylist = async () => {
    try {
      await axios.post('http://localhost:5000/api/songs/playlists', {
        title: newPlaylistTitle,
        userId: loggedInUser._id || loggedInUser.id,
        songIds: selectedSongIds
      });
      alert("Tạo playlist thành công!");
      setIsSelecting(false);
    } catch (err) { alert("Lỗi lưu playlist"); }
  };

  const playSong = (index) => {
    if (isSelecting) {
      toggleSongSelection(songs[index]._id);
      return;
    }
    setCurrentIndex(index);
    setIsPlaying(true);
  };

  return (
    <div style={{ padding: '30px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'Arial, sans-serif', paddingBottom: '120px' }}>
      
      {/* THANH CHỌN NHẠC (Selection Mode) */}
      {isSelecting && (
        <div style={selectionBarStyle}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            <span>Đang chọn cho: <b style={{ color: '#1db954' }}>{newPlaylistTitle}</b></span>
            <span style={countBadge}>{selectedSongIds.length} bài đã chọn</span>
          </div>
          <div style={{ display: 'flex', gap: '15px' }}>
            <button onClick={handleSavePlaylist} style={btnSave}>HOÀN TẤT</button>
            <button onClick={() => setIsSelecting(false)} style={btnCancel}><X size={20}/></button>
          </div>
        </div>
      )}

      {/* HEADER */}
      {!isSelecting && (
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
          <h1 style={{ color: '#1db954', margin: 0, display: 'flex', alignItems: 'center', gap: '10px' }}>
            <Music size={36} /> P2TUNES
          </h1>
          <button onClick={handleStartCreatePlaylist} style={btnPrimary}>
            <ListPlus size={18} strokeWidth={3} /> TẠO PLAYLIST
          </button>
        </div>
      )}

      {/* GRID DANH SÁCH NHẠC */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '30px' }}>
        {songs.map((song, index) => {
          const isSelected = selectedSongIds.includes(song._id);
          return (
            <div key={song._id} style={{...songCard, border: isSelected ? '3px solid #1db954' : '3px solid transparent'}} onClick={() => playSong(index)}>
              <div style={{ position: 'relative' }}>
                <img src={`http://localhost:5000${song.imageUrl}`} alt="" style={imgStyle} />
                {isSelecting ? (
                   <div style={checkIconContainer}>
                     {isSelected ? <CheckCircle2 color="#1db954" fill="white" size={32}/> : <Circle color="#ccc" size={32}/>}
                   </div>
                ) : (
                  <button style={playOverlayBtn}><Play fill="white" size={20} /></button>
                )}
              </div>
              <h3 style={{ margin: '15px 0 5px 0', fontSize: '17px' }}>{song.title}</h3>
              <p style={{ color: '#666', fontSize: '14px' }}>{song.artist}</p>
              {!isSelecting && (
                <button onClick={(e) => { e.stopPropagation(); handleLike(song._id); }} style={likeBtnStyle}>
                  <Heart size={20} fill={song.likes?.includes(loggedInUser?._id) ? "red" : "none"} color={song.likes?.includes(loggedInUser?._id) ? "red" : "#666"} />
                  <span>{song.likes?.length || 0}</span>
                </button>
              )}
            </div>
          );
        })}
      </div>

      {/* TRÌNH PHÁT NHẠC NÂNG CẤP */}
      {currentIndex !== -1 && !isSelecting && (
        <div style={playerContainer}>
          {/* 1. Thông tin bài hát */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px', width: '25%' }}>
            <img src={`http://localhost:5000${songs[currentIndex].imageUrl}`} style={{ width: '55px', height: '55px', borderRadius: '8px' }} alt="" />
            <div style={{ overflow: 'hidden' }}>
              <div style={{ fontWeight: 'bold', whiteSpace: 'nowrap', textOverflow: 'ellipsis' }}>{songs[currentIndex].title}</div>
              <div style={{ fontSize: '13px', color: '#888' }}>{songs[currentIndex].artist}</div>
            </div>
          </div>

          {/* 2. Bộ điều khiển trung tâm */}
          <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '25px' }}>
              <SkipBack size={24} style={{ cursor: 'pointer' }} onClick={handlePrev} />
              <button onClick={() => isPlaying ? audioRef.current.pause() : audioRef.current.play()} style={mainPlayBtn}>
                {isPlaying ? <Pause size={24} fill="white" /> : <Play size={24} fill="white" style={{marginLeft: '3px'}} />}
              </button>
              <SkipForward size={24} style={{ cursor: 'pointer' }} onClick={handleNext} />
            </div>
            
            {/* THANH THỜI LƯỢNG MÀU ĐEN */}
            <div style={{ display: 'flex', alignItems: 'center', width: '100%', maxWidth: '500px', gap: '10px' }}>
              <span style={{fontSize: '11px', color: '#666', width: '35px'}}>
                {audioRef.current ? Math.floor(audioRef.current.currentTime / 60) + ":" + ("0" + Math.floor(audioRef.current.currentTime % 60)).slice(-2) : "0:00"}
              </span>
              <input 
                type="range" 
                min="0" max="100" 
                value={progress} 
                onChange={handleSeek} 
                style={progressSlider} 
              />
              <span style={{fontSize: '11px', color: '#666', width: '35px'}}>
                {audioRef.current && !isNaN(audioRef.current.duration) ? Math.floor(audioRef.current.duration / 60) + ":" + ("0" + Math.floor(audioRef.current.duration % 60)).slice(-2) : "0:00"}
              </span>
            </div>
          </div>

          <div style={{ width: '25%' }}></div>

          <audio 
            ref={audioRef} 
            src={`http://localhost:5000${songs[currentIndex].songUrl}`} 
            onPlay={() => setIsPlaying(true)}
            onPause={() => setIsPlaying(false)}
            onTimeUpdate={onTimeUpdate}
            onEnded={handleNext}
            autoPlay
          />
        </div>
      )}
    </div>
  );
};

/* --- STYLES --- */
const progressSlider = {
  flex: 1,
  appearance: 'none',
  height: '5px',
  background: '#000000', // THANH THỜI LƯỢNG MÀU ĐEN
  borderRadius: '5px',
  outline: 'none',
  cursor: 'pointer',
  accentColor: '#1db954'
};

const playerContainer = {
  position: 'fixed', bottom: 0, left: 0, right: 0,
  background: '#ffffff', borderTop: '1px solid #eee',
  padding: '15px 40px', display: 'flex', alignItems: 'center', zIndex: 1000,
  boxShadow: '0 -5px 20px rgba(0,0,0,0.05)'
};

const mainPlayBtn = {
  background: '#1db954', color: 'white', border: 'none',
  width: '45px', height: '45px', borderRadius: '50%',
  display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer'
};

const selectionBarStyle = {
  position: 'fixed', top: 0, left: 0, right: 0, height: '70px',
  backgroundColor: '#111', color: '#fff', display: 'flex',
  alignItems: 'center', justifyContent: 'space-between', padding: '0 40px', zIndex: 2000
};

const countBadge = { background: '#333', padding: '4px 12px', borderRadius: '12px', fontSize: '13px', border: '1px solid #1db954' };
const btnSave = { background: '#1db954', color: 'white', border: 'none', padding: '10px 25px', borderRadius: '20px', fontWeight: 'bold', cursor: 'pointer' };
const btnCancel = { background: '#ff4444', color: 'white', border: 'none', width: '35px', height: '35px', borderRadius: '50%', cursor: 'pointer' };

const btnPrimary = { 
  background: '#ffffff', color: '#000000', border: '2px solid #000', 
  padding: '10px 20px', borderRadius: '25px', fontWeight: '900', 
  cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' 
};

const songCard = { background: '#fff', padding: '15px', borderRadius: '15px', boxShadow: '0 5px 15px rgba(0,0,0,0.05)', cursor: 'pointer' };
const imgStyle = { width: '100%', aspectRatio: '1/1', objectFit: 'cover', borderRadius: '10px' };
const playOverlayBtn = { position: 'absolute', bottom: '10px', right: '10px', background: '#1db954', border: 'none', borderRadius: '50%', width: '40px', height: '40px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white' };
const checkIconContainer = { position: 'absolute', top: '10px', right: '10px' };
const likeBtnStyle = { background: 'none', border: 'none', display: 'flex', alignItems: 'center', gap: '5px', cursor: 'pointer', marginTop: '10px' };

export default Home;
